<?php require __DIR__.'/../includes/bootstrap.php'; if(($_SESSION['role']??'')!=='admin'){http_response_code(403);exit('Forbidden');} $db=App::get('db'); $stats=['users'=>$db->query('SELECT COUNT(*) FROM users')->fetchColumn(),'videos'=>$db->query('SELECT COUNT(*) FROM videos')->fetchColumn(),'withdrawals'=>$db->query("SELECT COUNT(*) FROM withdrawals WHERE status='pending'")->fetchColumn(),'ads'=>$db->query("SELECT COUNT(*) FROM ad_campaigns WHERE status='pending'")->fetchColumn()]; ?><!doctype html><html><head><title>Admin</title><link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css" rel="stylesheet"></head><body class="p-4"><h1>Admin Dashboard</h1><div class="row"><?php foreach($stats as $k=>$v): ?><div class="col-md-3"><div class="card card-body"><strong><?= htmlspecialchars(ucfirst($k)) ?></strong><span class="display-6"><?= (int)$v ?></span></div></div><?php endforeach; ?></div><p class="mt-4">Manage users, videos, reports, withdrawals, crypto settings, ads, roles, logs, SMTP, cache, themes, languages, backups, and analytics from this secured panel.</p></body></html>
